function twoSum(nums, target) {
  const seen = new Map();

  for (let i = 0; i < nums.length; i++) {
    const current = nums[i];
    const need = target - current;

    // Have we already seen the required number?
    if (seen.has(need)) {
      return [seen.get(need), i];
    }

    // Store current number and its index
    seen.set(current, i);
  }
}

